{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track daily meals, calories, and macronutrient categories with weekly chart visualization",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "^0.1.0"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber';

export type FoodItem = {
  name: string;
  calories: number;
  categories: FoodCategory[];
};

export type Meal = {
  id: string;
  name: string;
  items: FoodItem[];
  timestamp: string; // ISO 8601
};

export type DailyGoal = {
  calories: number;
  updatedAt: string; // ISO 8601
};

export type DailySummary = {
  date: string; // YYYY-MM-DD
  meals: Meal[];
  totalCalories: number;
  categoryBreakdown: Record<FoodCategory, number>;
  goal: number | null;
};

export type WeeklyData = {
  days: {
    date: string;
    totalCalories: number;
  }[];
  goal: number | null;
};

export type StoreData = {
  meals: Meal[];
  goal: DailyGoal | null;
};

import type { Meal, DailyGoal, StoreData } from './types';

const DATA_DIR = new URL('./data/', import.meta.url).pathname;
const MEALS_PATH = `${DATA_DIR}meals.jsonl`;
const GOAL_PATH = `${DATA_DIR}goal.json`;

export const loadMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH);
  if (!(await file.exists())) return [];

  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Meal);
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_PATH);
  const existing = (await file.exists()) ? await file.text() : '';
  const line = JSON.stringify(meal) + '\n';
  await Bun.write(MEALS_PATH, existing + line);
};

export const deleteMeal = async (mealId: string): Promise<boolean> => {
  const meals = await loadMeals();
  const filtered = meals.filter((m) => m.id !== mealId);
  if (filtered.length === meals.length) return false;

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length ? '\n' : '');
  await Bun.write(MEALS_PATH, content);
  return true;
};

export const loadGoal = async (): Promise<DailyGoal | null> => {
  const file = Bun.file(GOAL_PATH);
  if (!(await file.exists())) return null;

  const text = await file.text();
  return JSON.parse(text) as DailyGoal;
};

export const saveGoal = async (goal: DailyGoal): Promise<void> => {
  await Bun.write(GOAL_PATH, JSON.stringify(goal, null, 2));
};

export const loadAll = async (): Promise<StoreData> => {
  const [meals, goal] = await Promise.all([loadMeals(), loadGoal()]);
  return { meals, goal };
};

import type { Meal, FoodItem, FoodCategory, DailySummary, WeeklyData, DailyGoal } from './types';
import { loadMeals, appendMeal, deleteMeal, loadGoal, saveGoal } from './store';

const generateId = (): string => crypto.randomUUID();

const toDateString = (iso: string): string => iso.slice(0, 10);

const today = (): string => new Date().toISOString().slice(0, 10);

export const logMeal = async (name: string, items: FoodItem[], timestamp?: string): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    name,
    items,
    timestamp: timestamp ?? new Date().toISOString(),
  };
  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (mealId: string): Promise<boolean> => {
  return deleteMeal(mealId);
};

export const setDailyGoal = async (calories: number): Promise<DailyGoal> => {
  const goal: DailyGoal = {
    calories,
    updatedAt: new Date().toISOString(),
  };
  await saveGoal(goal);
  return goal;
};

export const getDailyGoal = async (): Promise<DailyGoal | null> => {
  return loadGoal();
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? today();
  const [meals, goal] = await Promise.all([loadMeals(), loadGoal()]);

  const dayMeals = meals.filter((m) => toDateString(m.timestamp) === targetDate);

  let totalCalories = 0;
  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  for (const meal of dayMeals) {
    for (const item of meal.items) {
      totalCalories += item.calories;
      for (const cat of item.categories) {
        categoryBreakdown[cat] += item.calories;
      }
    }
  }

  return {
    date: targetDate,
    meals: dayMeals,
    totalCalories,
    categoryBreakdown,
    goal: goal?.calories ?? null,
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date();
  const [meals, goal] = await Promise.all([loadMeals(), loadGoal()]);

  const days: WeeklyData['days'] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);

    const dayMeals = meals.filter((m) => toDateString(m.timestamp) === dateStr);
    const totalCalories = dayMeals.reduce(
      (sum, meal) => sum + meal.items.reduce((s, item) => s + item.calories, 0),
      0
    );

    days.push({ date: dateStr, totalCalories });
  }

  return { days, goal: goal?.calories ?? null };
};

import { h } from 'plaited';
import type { WeeklyData } from './types';

const CHART_HEIGHT = 200;
const BAR_WIDTH = 40;
const GAP = 12;
const LABEL_HEIGHT = 24;
const PADDING = 16;

const COLORS = {
  bar: '#4ade80',
  barOver: '#f87171',
  goalLine: '#facc15',
  label: '#94a3b8',
  value: '#e2e8f0',
  bg: '#1e293b',
};

export const renderWeeklyChart = (data: WeeklyData) => {
  const maxCalories = Math.max(
    ...data.days.map((d) => d.totalCalories),
    data.goal ?? 0,
    1
  );

  const chartWidth = data.days.length * (BAR_WIDTH + GAP) - GAP + PADDING * 2;
  const totalHeight = CHART_HEIGHT + LABEL_HEIGHT + PADDING * 2;

  const bars = data.days.map((day, i) => {
    const barHeight = (day.totalCalories / maxCalories) * CHART_HEIGHT;
    const x = PADDING + i * (BAR_WIDTH + GAP);
    const y = PADDING + CHART_HEIGHT - barHeight;
    const isOver = data.goal !== null && day.totalCalories > data.goal;
    const dayLabel = day.date.slice(5); // MM-DD

    return h('g', {},
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(BAR_WIDTH),
        height: String(Math.max(barHeight, 1)),
        fill: isOver ? COLORS.barOver : COLORS.bar,
        rx: '4',
      }),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(y - 6),
        fill: COLORS.value,
        'text-anchor': 'middle',
        'font-size': '11',
        'font-family': 'monospace',
      }, String(day.totalCalories)),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(PADDING + CHART_HEIGHT + 16),
        fill: COLORS.label,
        'text-anchor': 'middle',
        'font-size': '11',
        'font-family': 'monospace',
      }, dayLabel),
    );
  });

  const goalLine = data.goal !== null
    ? (() => {
        const goalY = PADDING + CHART_HEIGHT - (data.goal / maxCalories) * CHART_HEIGHT;
        return h('g', {},
          h('line', {
            x1: String(PADDING - 4),
            y1: String(goalY),
            x2: String(chartWidth - PADDING + 4),
            y2: String(goalY),
            stroke: COLORS.goalLine,
            'stroke-width': '2',
            'stroke-dasharray': '6,4',
          }),
          h('text', {
            x: String(chartWidth - PADDING + 8),
            y: String(goalY + 4),
            fill: COLORS.goalLine,
            'font-size': '11',
            'font-family': 'monospace',
          }, `${data.goal} goal`),
        );
      })()
    : null;

  return h('svg', {
    width: String(chartWidth + 60),
    height: String(totalHeight),
    viewBox: `0 0 ${chartWidth + 60} ${totalHeight}`,
    xmlns: 'http://www.w3.org/2000/svg',
  },
    h('rect', {
      width: '100%',
      height: '100%',
      fill: COLORS.bg,
      rx: '8',
    }),
    ...bars,
    ...(goalLine ? [goalLine] : []),
  );
};

import { h, createSSR } from 'plaited';
import type { DailySummary, FoodCategory } from './types';
import { renderWeeklyChart } from './chart';
import { getDailySummary, getWeeklyData } from './tracker';

const CATEGORY_COLORS: Record<FoodCategory, string> = {
  protein: '#60a5fa',
  carbs: '#fbbf24',
  fat: '#f87171',
  fiber: '#34d399',
};

const renderCategoryTag = (category: FoodCategory) =>
  h('span', {
    style: `display:inline-block;padding:2px 8px;border-radius:9999px;font-size:12px;margin-right:4px;color:#fff;background:${CATEGORY_COLORS[category]}`,
  }, category);

const renderMealCard = (meal: DailySummary['meals'][number]) => {
  const mealCalories = meal.items.reduce((s, item) => s + item.calories, 0);

  return h('div', {
    style: 'background:#334155;border-radius:8px;padding:12px 16px;margin-bottom:8px',
  },
    h('div', { style: 'display:flex;justify-content:space-between;align-items:center;margin-bottom:8px' },
      h('strong', { style: 'color:#f1f5f9;font-size:16px' }, meal.name),
      h('span', { style: 'color:#94a3b8;font-size:13px' },
        new Date(meal.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      ),
    ),
    ...meal.items.map((item) =>
      h('div', {
        style: 'display:flex;justify-content:space-between;align-items:center;padding:4px 0;border-top:1px solid #475569',
      },
        h('div', {},
          h('span', { style: 'color:#e2e8f0;margin-right:8px' }, item.name),
          ...item.categories.map(renderCategoryTag),
        ),
        h('span', { style: 'color:#cbd5e1;font-family:monospace' }, `${item.calories} kcal`),
      ),
    ),
    h('div', {
      style: 'text-align:right;margin-top:8px;color:#f1f5f9;font-weight:bold;font-size:14px',
    }, `${mealCalories} kcal`),
  );
};

const renderProgressBar = (current: number, goal: number) => {
  const pct = Math.min((current / goal) * 100, 100);
  const isOver = current > goal;
  const barColor = isOver ? '#f87171' : '#4ade80';

  return h('div', { style: 'margin:12px 0' },
    h('div', { style: 'display:flex;justify-content:space-between;font-size:13px;color:#94a3b8;margin-bottom:4px' },
      h('span', {}, `${current} kcal consumed`),
      h('span', {}, `${goal} kcal goal`),
    ),
    h('div', { style: 'background:#1e293b;border-radius:9999px;height:12px;overflow:hidden' },
      h('div', {
        style: `width:${pct}%;height:100%;background:${barColor};border-radius:9999px;transition:width 0.3s`,
      }),
    ),
    isOver
      ? h('div', { style: 'color:#f87171;font-size:12px;margin-top:4px' },
          `Over goal by ${current - goal} kcal`,
        )
      : h('div', { style: 'color:#4ade80;font-size:12px;margin-top:4px' },
          `${goal - current} kcal remaining`,
        ),
  );
};

const renderCategoryBreakdown = (breakdown: DailySummary['categoryBreakdown']) => {
  const categories = Object.entries(breakdown).filter(([, v]) => v > 0) as [FoodCategory, number][];
  if (categories.length === 0) return h('div', {}, '');

  return h('div', { style: 'display:flex;gap:16px;flex-wrap:wrap;margin:12px 0' },
    ...categories.map(([cat, cal]) =>
      h('div', { style: 'text-align:center' },
        h('div', {
          style: `width:48px;height:48px;border-radius:50%;background:${CATEGORY_COLORS[cat]};display:flex;align-items:center;justify-content:center;color:#fff;font-size:13px;font-weight:bold;margin:0 auto 4px`,
        }, String(cal)),
        h('div', { style: 'color:#94a3b8;font-size:11px;text-transform:capitalize' }, cat),
      ),
    ),
  );
};

export const renderDailyView = async (date?: string) => {
  const summary = await getDailySummary(date);

  const content = h('div', { style: 'font-family:system-ui,sans-serif;background:#0f172a;color:#f1f5f9;padding:20px;max-width:480px;margin:0 auto;border-radius:12px' },
    h('h2', { style: 'margin:0 0 4px;font-size:20px' }, 'Daily Diet Tracker'),
    h('p', { style: 'color:#64748b;margin:0 0 16px;font-size:14px' }, summary.date),
    summary.goal !== null
      ? renderProgressBar(summary.totalCalories, summary.goal)
      : h('div', { style: 'color:#94a3b8;font-size:14px;margin:8px 0' },
          `Total: ${summary.totalCalories} kcal (no goal set)`,
        ),
    renderCategoryBreakdown(summary.categoryBreakdown),
    h('h3', { style: 'font-size:16px;margin:16px 0 8px;color:#94a3b8' },
      `Meals (${summary.meals.length})`,
    ),
    summary.meals.length > 0
      ? h('div', {}, ...summary.meals.map(renderMealCard))
      : h('div', { style: 'color:#475569;font-style:italic;padding:20px 0;text-align:center' },
          'No meals logged yet today',
        ),
  );

  const { render } = createSSR();
  return render(content);
};

export const renderWeeklyView = async (endDate?: string) => {
  const weeklyData = await getWeeklyData(endDate);
  const chart = renderWeeklyChart(weeklyData);

  const totalWeekly = weeklyData.days.reduce((s, d) => s + d.totalCalories, 0);
  const avgDaily = Math.round(totalWeekly / 7);

  const content = h('div', { style: 'font-family:system-ui,sans-serif;background:#0f172a;color:#f1f5f9;padding:20px;max-width:520px;margin:0 auto;border-radius:12px' },
    h('h2', { style: 'margin:0 0 4px;font-size:20px' }, 'Weekly Calorie Overview'),
    h('p', { style: 'color:#64748b;margin:0 0 16px;font-size:14px' },
      `${weeklyData.days[0]?.date ?? ''} — ${weeklyData.days[6]?.date ?? ''}`,
    ),
    h('div', { style: 'display:flex;gap:24px;margin-bottom:16px' },
      h('div', {},
        h('div', { style: 'color:#94a3b8;font-size:12px' }, 'Weekly Total'),
        h('div', { style: 'font-size:24px;font-weight:bold' }, `${totalWeekly}`),
      ),
      h('div', {},
        h('div', { style: 'color:#94a3b8;font-size:12px' }, 'Daily Average'),
        h('div', { style: 'font-size:24px;font-weight:bold' }, `${avgDaily}`),
      ),
      weeklyData.goal !== null
        ? h('div', {},
            h('div', { style: 'color:#94a3b8;font-size:12px' }, 'Daily Goal'),
            h('div', { style: 'font-size:24px;font-weight:bold;color:#facc15' }, `${weeklyData.goal}`),
          )
        : h('span', {}),
    ),
    chart,
  );

  const { render } = createSSR();
  return render(content);
};

export type { FoodCategory, FoodItem, Meal, DailyGoal, DailySummary, WeeklyData } from './types';
export { logMeal, removeMeal, setDailyGoal, getDailyGoal, getDailySummary, getWeeklyData } from './tracker';
export { renderDailyView, renderWeeklyView } from './render';
export { renderWeeklyChart } from './chart';

{
  "name": "@node/chart-generator",
  "version": "1.0.0",
  "description": "Generate bar, line, and pie charts from JSON data with auto field detection",
  "main": "index.ts",
  "modnet": {
    "contentType": "science",
    "structure": "form",
    "mechanics": ["chart"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "@plaited/template": "latest",
    "@plaited/ssr": "latest"
  }
}

import type { DetectedField, FieldType } from './types'

const detectFieldType = (values: unknown[]): FieldType => {
  const valid = values.filter(v => v !== null && v !== undefined)
  if (valid.length === 0) return 'categorical'
  const numericCount = valid.filter(v =>
    typeof v === 'number' ||
    (typeof v === 'string' && !isNaN(Number(v)) && v.trim() !== '')
  ).length
  return numericCount / valid.length > 0.8 ? 'numeric' : 'categorical'
}

export const detectFields = (data: Record<string, unknown>[]): DetectedField[] => {
  if (!data.length) return []
  return Object.keys(data[0]).map(name => ({
    name,
    type: detectFieldType(data.map(row => row[name])),
  }))
}

import { h } from '@plaited/template'
import type { ChartConfig, ChartData } from './types'

const DEFAULT_COLORS = [
  '#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f',
  '#edc948', '#b07aa1', '#ff9da7', '#9c755f', '#bab0ac',
]

const PAD = { top: 60, right: 30, bottom: 70, left: 70 }

const getColor = (i: number, colors: string[]): string => {
  const p = colors.length > 0 ? colors : DEFAULT_COLORS
  return p[i % p.length]
}

const formatNum = (n: number): string => {
  if (Math.abs(n) >= 1e6) return (n / 1e6).toFixed(1) + 'M'
  if (Math.abs(n) >= 1e3) return (n / 1e3).toFixed(1) + 'K'
  if (Number.isInteger(n)) return String(n)
  return n.toFixed(1)
}

const truncate = (s: string, max: number): string =>
  s.length > max ? s.slice(0, max - 1) + '\u2026' : s

const niceMax = (val: number): number => {
  if (val <= 0) return 1
  const mag = Math.pow(10, Math.floor(Math.log10(val)))
  const norm = val / mag
  if (norm <= 1) return mag
  if (norm <= 2) return 2 * mag
  if (norm <= 5) return 5 * mag
  return 10 * mag
}

const svgText = (
  x: number,
  y: number,
  content: string,
  attrs: Record<string, string> = {},
) =>
  h(
    'text',
    {
      x: String(x),
      y: String(y),
      'font-family': 'system-ui, -apple-system, sans-serif',
      'font-size': '12',
      fill: '#555',
      ...attrs,
    },
    content,
  )

// ─── Bar Chart ───────────────────────────────────────────────

const renderBarChart = (config: ChartConfig, data: ChartData) => {
  const { width, height, title, xLabel, yLabel, xField, yField, colors } = config
  const cw = width - PAD.left - PAD.right
  const ch = height - PAD.top - PAD.bottom

  const labels = data.map(d => String(d[xField] ?? ''))
  const values = data.map(d => Number(d[yField]) || 0)
  const max = niceMax(Math.max(...values, 0))
  const n = labels.length
  const groupW = cw / Math.max(n, 1)
  const barW = groupW * 0.65
  const gap = groupW * 0.35

  const tickCount = 5
  const gridLines = Array.from({ length: tickCount + 1 }, (_, i) => {
    const val = (max / tickCount) * i
    const y = PAD.top + ch - (ch * i) / tickCount
    return [
      h('line', {
        x1: String(PAD.left),
        y1: String(y),
        x2: String(PAD.left + cw),
        y2: String(y),
        stroke: '#eaeaea',
        'stroke-width': '1',
      }),
      svgText(PAD.left - 8, y + 4, formatNum(val), {
        'text-anchor': 'end',
        'font-size': '11',
      }),
    ]
  }).flat()

  const bars = values.map((v, i) => {
    const barH = max > 0 ? (v / max) * ch : 0
    const x = PAD.left + i * groupW + gap / 2
    const y = PAD.top + ch - barH
    return h('rect', {
      x: String(x),
      y: String(y),
      width: String(barW),
      height: String(Math.max(barH, 0)),
      fill: getColor(i, colors),
      rx: '3',
    })
  })

  const xLabels = labels.map((label, i) => {
    const x = PAD.left + i * groupW + groupW / 2
    return svgText(x, PAD.top + ch + 22, truncate(label, 14), {
      'text-anchor': 'middle',
      'font-size': '11',
    })
  })

  return h(
    'svg',
    {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
    },
    h('rect', { width: '100%', height: '100%', fill: 'white' }),
    ...gridLines,
    h('line', {
      x1: String(PAD.left),
      y1: String(PAD.top),
      x2: String(PAD.left),
      y2: String(PAD.top + ch),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(PAD.left),
      y1: String(PAD.top + ch),
      x2: String(PAD.left + cw),
      y2: String(PAD.top + ch),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    ...bars,
    ...xLabels,
    svgText(width / 2, 32, title, {
      'text-anchor': 'middle',
      'font-size': '18',
      'font-weight': 'bold',
      fill: '#1a1a1a',
    }),
    svgText(width / 2, height - 10, xLabel, {
      'text-anchor': 'middle',
      'font-size': '13',
    }),
    svgText(16, height / 2, yLabel, {
      'text-anchor': 'middle',
      'font-size': '13',
      transform: `rotate(-90, 16, ${height / 2})`,
    }),
  )
}

// ─── Line Chart ──────────────────────────────────────────────

const renderLineChart = (config: ChartConfig, data: ChartData) => {
  const { width, height, title, xLabel, yLabel, xField, yField, colors } = config
  const cw = width - PAD.left - PAD.right
  const ch = height - PAD.top - PAD.bottom

  const labels = data.map(d => String(d[xField] ?? ''))
  const values = data.map(d => Number(d[yField]) || 0)
  const maxRaw = Math.max(...values, 0)
  const minRaw = Math.min(...values, 0)
  const max = niceMax(maxRaw)
  const min = minRaw < 0 ? -niceMax(Math.abs(minRaw)) : 0
  const range = max - min || 1

  const points = values.map((v, i) => ({
    x: PAD.left + (i / Math.max(values.length - 1, 1)) * cw,
    y: PAD.top + ch - ((v - min) / range) * ch,
  }))

  const polyline = points.map(p => `${p.x},${p.y}`).join(' ')

  // Area fill under line
  const areaPath = [
    `M ${points[0]?.x ?? PAD.left} ${PAD.top + ch}`,
    ...points.map(p => `L ${p.x} ${p.y}`),
    `L ${points[points.length - 1]?.x ?? PAD.left + cw} ${PAD.top + ch}`,
    'Z',
  ].join(' ')

  const tickCount = 5
  const gridLines = Array.from({ length: tickCount + 1 }, (_, i) => {
    const val = min + (range / tickCount) * i
    const y = PAD.top + ch - ((val - min) / range) * ch
    return [
      h('line', {
        x1: String(PAD.left),
        y1: String(y),
        x2: String(PAD.left + cw),
        y2: String(y),
        stroke: '#eaeaea',
        'stroke-width': '1',
      }),
      svgText(PAD.left - 8, y + 4, formatNum(val), {
        'text-anchor': 'end',
        'font-size': '11',
      }),
    ]
  }).flat()

  const xLabels = labels.map((label, i) => {
    const x = PAD.left + (i / Math.max(labels.length - 1, 1)) * cw
    return svgText(x, PAD.top + ch + 22, truncate(label, 12), {
      'text-anchor': 'middle',
      'font-size': '11',
    })
  })

  const lineColor = getColor(0, colors)

  const dots = points.map(p =>
    h('circle', {
      cx: String(p.x),
      cy: String(p.y),
      r: '4.5',
      fill: lineColor,
      stroke: 'white',
      'stroke-width': '2',
    }),
  )

  return h(
    'svg',
    {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
    },
    h('rect', { width: '100%', height: '100%', fill: 'white' }),
    ...gridLines,
    h('line', {
      x1: String(PAD.left),
      y1: String(PAD.top),
      x2: String(PAD.left),
      y2: String(PAD.top + ch),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(PAD.left),
      y1: String(PAD.top + ch),
      x2: String(PAD.left + cw),
      y2: String(PAD.top + ch),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    h('path', {
      d: areaPath,
      fill: lineColor,
      opacity: '0.08',
    }),
    h('polyline', {
      points: polyline,
      fill: 'none',
      stroke: lineColor,
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
    }),
    ...dots,
    ...xLabels,
    svgText(width / 2, 32, title, {
      'text-anchor': 'middle',
      'font-size': '18',
      'font-weight': 'bold',
      fill: '#1a1a1a',
    }),
    svgText(width / 2, height - 10, xLabel, {
      'text-anchor': 'middle',
      'font-size': '13',
    }),
    svgText(16, height / 2, yLabel, {
      'text-anchor': 'middle',
      'font-size': '13',
      transform: `rotate(-90, 16, ${height / 2})`,
    }),
  )
}

// ─── Pie Chart ───────────────────────────────────────────────

const renderPieChart = (config: ChartConfig, data: ChartData) => {
  const { width, height, title, xField, yField, colors } = config
  const cx = width / 2
  const cy = height / 2 + 10
  const radius = Math.min(width, height) / 2 - 80

  const labels = data.map(d => String(d[xField] ?? ''))
  const values = data.map(d => Math.abs(Number(d[yField]) || 0))
  const total = values.reduce((s, v) => s + v, 0) || 1

  let currentAngle = -Math.PI / 2 // start at 12 o'clock

  const slices = values.map((val, i) => {
    const sliceAngle = (val / total) * Math.PI * 2
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    // Full circle special case
    const d =
      val === total
        ? [
            `M ${cx - radius} ${cy}`,
            `A ${radius} ${radius} 0 1 1 ${cx + radius} ${cy}`,
            `A ${radius} ${radius} 0 1 1 ${cx - radius} ${cy}`,
          ].join(' ')
        : `M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`

    const midAngle = startAngle + sliceAngle / 2
    const pct = ((val / total) * 100).toFixed(1)

    return {
      d,
      color: getColor(i, colors),
      label: labels[i],
      pct,
      midAngle,
      val,
    }
  })

  const slicePaths = slices.map(s =>
    h('path', { d: s.d, fill: s.color, stroke: 'white', 'stroke-width': '2' }),
  )

  const sliceLabels = slices
    .filter(s => Number(s.pct) > 4)
    .map(s => {
      const labelR = radius + 28
      const lx = cx + labelR * Math.cos(s.midAngle)
      const ly = cy + labelR * Math.sin(s.midAngle)
      return svgText(lx, ly + 4, `${truncate(s.label, 10)} ${s.pct}%`, {
        'text-anchor': s.midAngle > Math.PI / 2 && s.midAngle < (3 * Math.PI) / 2 ? 'end' : 'start',
        'font-size': '11',
        fill: '#444',
      })
    })

  // Legend
  const legendX = 16
  const legendY = height - 30
  const legendItems = slices.map((s, i) => [
    h('rect', {
      x: String(legendX + i * 120),
      y: String(legendY - 10),
      width: '12',
      height: '12',
      fill: s.color,
      rx: '2',
    }),
    svgText(legendX + i * 120 + 18, legendY, truncate(s.label, 12), {
      'font-size': '11',
      fill: '#555',
    }),
  ]).flat()

  return h(
    'svg',
    {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
    },
    h('rect', { width: '100%', height: '100%', fill: 'white' }),
    ...slicePaths,
    ...sliceLabels,
    ...legendItems,
    svgText(width / 2, 32, title, {
      'text-anchor': 'middle',
      'font-size': '18',
      'font-weight': 'bold',
      fill: '#1a1a1a',
    }),
  )
}

// ─── Dispatcher ──────────────────────────────────────────────

export const renderChart = (config: ChartConfig, data: ChartData) => {
  switch (config.type) {
    case 'bar':
      return renderBarChart(config, data)
    case 'line':
      return renderLineChart(config, data)
    case 'pie':
      return renderPieChart(config, data)
  }
}

