const EDITOR_SCRIPT = `
(function(){
var ta=document.getElementById('json-editor');
var hi=document.getElementById('json-highlighted');
var err=document.getElementById('json-error');
var COLORS={key:'#881391',string:'#0b7c34',number:'#1750eb',boolean:'#d63200',null:'#808080'};
function esc(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}
function highlight(src){
  var tokens=[];
  var re=/("(?:[^"\\\\]|\\\\.)*")(\\s*:)?|(-?\\d+\\.?\\d*(?:[eE][+-]?\\d+)?)|\\b(true|false)\\b|\\b(null)\\b/g;
  var last=0,m;
  while((m=re.exec(src))!==null){
    if(m.index>last)tokens.push({t:src.slice(last,m.index),c:null});
    if(m[1]){tokens.push({t:m[1],c:m[2]?'key':'string'});if(m[2])tokens.push({t:m[2],c:null})}
    else if(m[3])tokens.push({t:m[3],c:'number'});
    else if(m[4])tokens.push({t:m[4],c:'boolean'});
    else if(m[5])tokens.push({t:m[5],c:'null'});
    last=re.lastIndex;
  }
  if(last<src.length)tokens.push({t:src.slice(last),c:null});
  return tokens.map(function(tk){
    var e=esc(tk.t);
    return tk.c?'<span style="color:'+COLORS[tk.c]+'">'+e+'</span>':e;
  }).join('');
}
function sync(){hi.innerHTML=highlight(ta.value)+'\\n'}
ta.addEventListener('input',sync);
ta.addEventListener('scroll',function(){hi.scrollTop=ta.scrollTop;hi.scrollLeft=ta.scrollLeft});
ta.addEventListener('input',function(){
  try{
    var data=JSON.parse(ta.value);
    if(Array.isArray(data)&&data.length>0){
      var keys=Object.keys(data[0]);
      ['xField','yField'].forEach(function(id){
        var sel=document.getElementById(id);
        var cur=sel.value;
        sel.innerHTML='';
        keys.forEach(function(k){
          var vals=data.map(function(d){return d[k]});
          var nc=vals.filter(function(v){return typeof v==='number'||(typeof v==='string'&&!isNaN(Number(v))&&v.trim()!=='')}).length;
          var type=nc/vals.length>0.8?'numeric':'categorical';
          var opt=document.createElement('option');
          opt.value=k;opt.textContent=k+' ('+type+')';
          if(k===cur)opt.selected=true;
          sel.appendChild(opt);
        });
      });
      err.textContent='';
    }
  }catch(e){err.textContent='Invalid JSON: '+e.message}
});
sync();
})();
`

