          h('div', { class: 'radio-group' }, ...chartTypeOptions),
          h('label', { class: 'field-label', for: 'title' }, 'Title'),
          h('input', {
            type: 'text',
            name: 'title',
            id: 'title',
            value: config?.title ?? 'My Chart',
            class: 'input',
          }),
          h('label', { class: 'field-label', for: 'xLabel' }, 'X-Axis Label'),
          h('input', {
            type: 'text',
            name: 'xLabel',
            id: 'xLabel',
            value: config?.xLabel ?? '',
