            id: 'yLabel',
            value: config?.yLabel ?? '',
            class: 'input',
          }),
          h('label', { class: 'field-label', for: 'xField' }, 'Category Field (X)'),
          h(
            'select',
            { name: 'xField', id: 'xField', class: 'input' },
            ...fieldOptions(config?.xField ?? defaultX),
          ),
          h('label', { class: 'field-label', for: 'yField' }, 'Value Field (Y)'),
          h(
            'select',
            { name: 'yField', id: 'yField', class: 'input' },
            ...fieldOptions(config?.yField ?? defaultY),
          ),
          h('label', { class: 'field-label', for: 'colors' }, 'Colors (comma-separated hex)'),
          h('input', {
            type: 'text',
