import { createSSR } from '@plaited/ssr'
import { renderChart } from './chart-engine'
import { renderPage } from './ui'
import { detectFields } from './field-detector'
import type { ChartConfig, ChartData, ChartType } from './types'

const SAMPLE_PATH = './data/sample.json'
const LATEST_SVG_PATH = './data/latest.svg'

const sampleData: ChartData = await Bun.file(SAMPLE_PATH).json()

let latestSvgString = ''

const parseColors = (raw: string): string[] =>
  raw
    .split(',')
    .map(c => c.trim())
    .filter(c => /^#[0-9a-fA-F]{3,8}$/.test(c))

const parseData = (raw: string): { data: ChartData; error?: string } => {
  try {
    const parsed = JSON.parse(raw)
    if (!Array.isArray(parsed)) return { data: [], error: 'Data must be a JSON array' }
    if (parsed.length === 0) return { data: [], error: 'Array must not be empty' }
    if (typeof parsed[0] !== 'object' || parsed[0] === null)
      return { data: [], error: 'Array items must be objects' }
    return { data: parsed as ChartData }
  } catch (e) {
    return { data: [], error: `Invalid JSON: ${(e as Error).message}` }
  }
}

const renderSvgToString = (config: ChartConfig, data: ChartData): string => {
  const ssr = createSSR()
  const chartNode = renderChart(config, data)
  return ssr.render(chartNode)
}

const renderFullPage = (
  jsonStr: string,
  fields: ReturnType<typeof detectFields>,
  chartNode?: unknown,
  config?: { type: ChartType; title: string; xLabel: string; yLabel: string; xField: string; yField: string; colors: string },
  error?: string,
): string => {
  const ssr = createSSR()
  const page = renderPage({ jsonStr, fields, chartNode, config, error })
  return '<!DOCTYPE html>' + ssr.render(page)
}

Bun.serve({
  port: 3000,

  async fetch(req) {
    const url = new URL(req.url)

    // ── GET / ── landing page with sample data
    if (url.pathname === '/' && req.method === 'GET') {
      const jsonStr = JSON.stringify(sampleData, null, 2)
      const fields = detectFields(sampleData as Record<string, unknown>[])
      const html = renderFullPage(jsonStr, fields)
      return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
    }

    // ── POST /generate ── build chart from form data
    if (url.pathname === '/generate' && req.method === 'POST') {
      const form = await req.formData()
      const rawJson = (form.get('data') as string) ?? '[]'
      const { data, error } = parseData(rawJson)

      if (error || data.length === 0) {
        const fields = detectFields(data as Record<string, unknown>[])
        const html = renderFullPage(rawJson, fields, undefined, undefined, error)
        return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
      }

      const fields = detectFields(data as Record<string, unknown>[])
      const chartType = (form.get('chartType') as ChartType) ?? 'bar'
      const title = (form.get('title') as string) ?? 'My Chart'
      const xLabel = (form.get('xLabel') as string) ?? ''
      const yLabel = (form.get('yLabel') as string) ?? ''
      const xField = (form.get('xField') as string) ?? fields[0]?.name ?? ''
      const yField = (form.get('yField') as string) ?? fields[0]?.name ?? ''
      const colorsRaw = (form.get('colors') as string) ?? ''

      const config: ChartConfig = {
        type: chartType,
        title,
        xLabel,
        yLabel,
        xField,
        yField,
        colors: parseColors(colorsRaw),
        width: 720,
        height: 450,
      }

      const chartNode = renderChart(config, data)
      latestSvgString = renderSvgToString(config, data)

      // Persist SVG to disk
      await Bun.write(LATEST_SVG_PATH, latestSvgString)

      // Save chart record to history
      const historyLine = JSON.stringify({ config, createdAt: new Date().toISOString() })
      const historyFile = Bun.file('./data/history.jsonl')
      const existing = (await historyFile.exists()) ? await historyFile.text() : ''
      await Bun.write('./data/history.jsonl', existing + historyLine + '\n')

      const formConfig = { type: chartType, title, xLabel, yLabel, xField, yField, colors: colorsRaw }
      const html = renderFullPage(rawJson, fields, chartNode, formConfig)
      return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
    }

    // ── GET /download ── serve latest SVG
    if (url.pathname === '/download' && req.method === 'GET') {
      if (!latestSvgString) {
        return new Response('No chart generated yet', { status: 404 })
      }
      const svgContent = '<?xml version="1.0" encoding="UTF-8"?>\n' + latestSvgString
      return new Response(svgContent, {
        headers: {
          'content-type': 'image/svg+xml',
          'content-disposition': 'attachment; filename="chart.svg"',
        },
      })
    }

    return new Response('Not found', { status: 404 })
  },
})

