  KinematicValues,
} from './types'

const FIXED_DT = 0.001

export const createPendulumState = (params: PendulumParams): PendulumState => ({
  angle: params.initialAngle,
  angularVelocity: 0,
  angularAcceleration: -(params.gravity / params.length) * Math.sin(params.initialAngle),
})

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  let current = { ...state }
  const steps = Math.max(1, Math.round(dt / FIXED_DT))
  const h = dt / steps

  for (let i = 0; i < steps; i++) {
    const alpha1 = -(params.gravity / params.length) * Math.sin(current.angle) - params.damping * current.angularVelocity
    const omega_mid = current.angularVelocity + alpha1 * (h / 2)
    const angle_mid = current.angle + current.angularVelocity * (h / 2)

    const alpha2 = -(params.gravity / params.length) * Math.sin(angle_mid) - params.damping * omega_mid
    const omega_mid2 = current.angularVelocity + alpha2 * (h / 2)
    const angle_mid2 = current.angle + omega_mid * (h / 2)

    const alpha3 = -(params.gravity / params.length) * Math.sin(angle_mid2) - params.damping * omega_mid2
    const omega_end = current.angularVelocity + alpha3 * h
    const angle_end = current.angle + omega_mid2 * h

    const alpha4 = -(params.gravity / params.length) * Math.sin(angle_end) - params.damping * omega_end

    const newAngle = current.angle + (h / 6) * (current.angularVelocity + 2 * omega_mid + 2 * omega_mid2 + omega_end)
    const newOmega = current.angularVelocity + (h / 6) * (alpha1 + 2 * alpha2 + 2 * alpha3 + alpha4)

    current = {
      angle: newAngle,
      angularVelocity: newOmega,
      angularAcceleration: -(params.gravity / params.length) * Math.sin(newAngle) - params.damping * newOmega,
    }
  }

  return current
}

export const pendulumKinematics = (
  state: PendulumState,
  params: PendulumParams,
): KinematicValues => {
  const { length } = params
  const x = length * Math.sin(state.angle)
  const y = -length * Math.cos(state.angle)
  const tangentialVel = length * state.angularVelocity
  const tangentialAcc = length * state.angularAcceleration

  return {
    position: { x, y },
    velocity: {
      x: tangentialVel * Math.cos(state.angle),
      y: tangentialVel * Math.sin(state.angle),
    },
    acceleration: {
      x: tangentialAcc * Math.cos(state.angle),
      y: tangentialAcc * Math.sin(state.angle),
    },
  }
}

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const rad = (params.angle * Math.PI) / 180
  return {
    x: 0,
    y: params.height,
    vx: params.velocity * Math.cos(rad),
    vy: params.velocity * Math.sin(rad),
    trail: [{ x: 0, y: params.height }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const newVx = state.vx
  const newVy = state.vy - params.gravity * dt
  const newX = state.x + state.vx * dt + 0.5 * 0 * dt * dt
  const newY = state.y + state.vy * dt - 0.5 * params.gravity * dt * dt

  const landed = newY <= 0 && state.y >= 0 && (state.x > 0 || state.y > 0)
  const clampedY = landed ? 0 : newY

  const trail = [...state.trail, { x: newX, y: clampedY }]
  if (trail.length > 2000) trail.splice(0, trail.length - 2000)

  return {
    x: newX,
    y: clampedY,
    vx: landed ? 0 : newVx,
    vy: landed ? 0 : newVy,
    trail,
    landed,
  }
}

export const projectileKinematics = (
  state: ProjectileState,
  params: ProjectileParams,
): KinematicValues => ({
  position: { x: state.x, y: state.y },
  velocity: { x: state.vx, y: state.vy },
  acceleration: { x: 0, y: state.landed ? 0 : -params.gravity },
})

export const createSpringState = (params: SpringParams): SpringState => ({
  displacement: params.initialDisplacement,
  velocity: 0,
  acceleration: -(params.springConstant / params.mass) * params.initialDisplacement,
})

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  let current = { ...state }
  const steps = Math.max(1, Math.round(dt / FIXED_DT))
  const h = dt / steps

  for (let i = 0; i < steps; i++) {
    const k = params.springConstant
    const m = params.mass
    const d = params.damping

    const a1 = -(k / m) * current.displacement - (d / m) * current.velocity
    const v_mid = current.velocity + a1 * (h / 2)
    const x_mid = current.displacement + current.velocity * (h / 2)

    const a2 = -(k / m) * x_mid - (d / m) * v_mid
    const v_mid2 = current.velocity + a2 * (h / 2)
    const x_mid2 = current.displacement + v_mid * (h / 2)

    const a3 = -(k / m) * x_mid2 - (d / m) * v_mid2
    const v_end = current.velocity + a3 * h
    const x_end = current.displacement + v_mid2 * h

    const a4 = -(k / m) * x_end - (d / m) * v_end

    const newDisplacement = current.displacement + (h / 6) * (current.velocity + 2 * v_mid + 2 * v_mid2 + v_end)
    const newVelocity = current.velocity + (h / 6) * (a1 + 2 * a2 + 2 * a3 + a4)

    current = {
      displacement: newDisplacement,
      velocity: newVelocity,
      acceleration: -(k / m) * newDisplacement - (d / m) * newVelocity,
    }
  }

  return current
}

export const springKinematics = (state: SpringState): KinematicValues => ({
  position: { x: state.displacement, y: 0 },
  velocity: { x: state.velocity, y: 0 },
  acceleration: { x: state.acceleration, y: 0 },
})

