const renderKinematics = (k: KinematicValues, simType: SimulationType) => {
  const items: Array<{ label: string; value: string }> = []

  if (simType === 'pendulum') {
    const angle = Math.atan2(k.position.x, -k.position.y)
    const speed = Math.sqrt(k.velocity.x ** 2 + k.velocity.y ** 2)
    const acc = Math.sqrt(k.acceleration.x ** 2 + k.acceleration.y ** 2)
    items.push(
      { label: 'Angle (θ)', value: `${fmt(angle * (180 / Math.PI))}°` },
      { label: 'Position (x, y)', value: `(${fmt(k.position.x)}, ${fmt(k.position.y)}) m` },
      { label: 'Velocity', value: `${fmt(speed)} m/s` },
      { label: 'Acceleration', value: `${fmt(acc)} m/s²` },
    )
  } else if (simType === 'projectile') {
    const speed = Math.sqrt(k.velocity.x ** 2 + k.velocity.y ** 2)
    items.push(
      { label: 'Position (x)', value: `${fmt(k.position.x)} m` },
      { label: 'Position (y)', value: `${fmt(k.position.y)} m` },
      { label: 'Velocity (vx)', value: `${fmt(k.velocity.x)} m/s` },
      { label: 'Velocity (vy)', value: `${fmt(k.velocity.y)} m/s` },
      { label: 'Speed', value: `${fmt(speed)} m/s` },
      { label: 'Acceleration', value: `${fmt(k.acceleration.y)} m/s²` },
    )
  } else {
    items.push(
      { label: 'Displacement', value: `${fmt(k.position.x)} m` },
      { label: 'Velocity', value: `${fmt(k.velocity.x)} m/s` },
      { label: 'Acceleration', value: `${fmt(k.acceleration.x)} m/s²` },
    )
  }

  return h('div', { style: styleToStr(styles.readout), 'p-target': 'readout' },
    ...items.map(i => renderReadout(i.label, i.value)),
  )
}

