export const renderSVGPendulum = (state: PendulumState, params: PendulumParams): string => {
  const w = 600
  const hh = 450
  const cx = w / 2
  const cy = 60
  const scale = 120

  const bobX = cx + params.length * scale * Math.sin(state.angle)
  const bobY = cy + params.length * scale * Math.cos(state.angle)

  const gridLines: string[] = []
  for (let i = 0; i < w; i += 40) {
    gridLines.push(`<line x1="${i}" y1="0" x2="${i}" y2="${hh}" stroke="${colors.gridLine}" stroke-width="0.5"/>`)
  }
  for (let i = 0; i < hh; i += 40) {
    gridLines.push(`<line x1="0" y1="${i}" x2="${w}" y2="${i}" stroke="${colors.gridLine}" stroke-width="0.5"/>`)
  }

  return `<svg viewBox="0 0 ${w} ${hh}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:100%">
    ${gridLines.join('')}
    <circle cx="${cx}" cy="${cy}" r="6" fill="${colors.border}"/>
    <line x1="${cx}" y1="${cy}" x2="${bobX}" y2="${bobY}" stroke="${colors.textDim}" stroke-width="2" stroke-linecap="round"/>
    <circle cx="${bobX}" cy="${bobY}" r="18" fill="${colors.pendulumBob}"/>
    <circle cx="${bobX}" cy="${bobY}" r="18" fill="none" stroke="${colors.pendulumBob}" stroke-opacity="0.3" stroke-width="4"/>
    <path d="M ${cx - 50} ${cy} L ${cx + 50} ${cy}" stroke="${colors.border}" stroke-width="3" stroke-linecap="round"/>
    <text x="10" y="20" fill="${colors.textDim}" font-size="11" font-family="monospace">θ = ${(state.angle * 180 / Math.PI).toFixed(1)}°</text>
    <text x="10" y="36" fill="${colors.textDim}" font-size="11" font-family="monospace">ω = ${state.angularVelocity.toFixed(3)} rad/s</text>
  </svg>`
}

export const renderSVGProjectile = (state: ProjectileState, params: ProjectileParams): string => {
  const w = 600
  const hh = 450
  const margin = 40

  const maxRange = (params.velocity ** 2 * Math.sin(2 * params.angle * Math.PI / 180)) / params.gravity
  const maxHeight = (params.velocity ** 2 * Math.sin(params.angle * Math.PI / 180) ** 2) / (2 * params.gravity)
  const scaleX = (w - margin * 2) / Math.max(maxRange * 1.1, 1)
  const scaleY = (hh - margin * 2) / Math.max(maxHeight * 1.2, 1)
  const scale = Math.min(scaleX, scaleY)

  const groundY = hh - margin

  const toScreenX = (x: number) => margin + x * scale
  const toScreenY = (y: number) => groundY - y * scale

  const gridLines: string[] = []
  for (let i = 0; i < w; i += 40) {
    gridLines.push(`<line x1="${i}" y1="0" x2="${i}" y2="${hh}" stroke="${colors.gridLine}" stroke-width="0.5"/>`)
  }
  for (let i = 0; i < hh; i += 40) {
    gridLines.push(`<line x1="0" y1="${i}" x2="${w}" y2="${i}" stroke="${colors.gridLine}" stroke-width="0.5"/>`)
  }

  let trailPath = ''
  if (state.trail.length > 1) {
    const points = state.trail.map(p => `${toScreenX(p.x)},${toScreenY(p.y)}`).join(' ')
    trailPath = `<polyline points="${points}" fill="none" stroke="${colors.trajectory}" stroke-width="2" stroke-opacity="0.7"/>`
  }

  const px = toScreenX(state.x)
  const py = toScreenY(state.y)

  return `<svg viewBox="0 0 ${w} ${hh}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:100%">
    ${gridLines.join('')}
    <line x1="${margin}" y1="${groundY}" x2="${w - margin}" y2="${groundY}" stroke="${colors.border}" stroke-width="2"/>
    <line x1="${margin}" y1="${margin}" x2="${margin}" y2="${groundY}" stroke="${colors.border}" stroke-width="1" stroke-dasharray="4"/>
    ${trailPath}
    <circle cx="${px}" cy="${py}" r="8" fill="${colors.trajectory}"/>
    <circle cx="${px}" cy="${py}" r="8" fill="none" stroke="${colors.trajectory}" stroke-opacity="0.3" stroke-width="3"/>
    <text x="10" y="20" fill="${colors.textDim}" font-size="11" font-family="monospace">x = ${state.x.toFixed(1)} m</text>
    <text x="10" y="36" fill="${colors.textDim}" font-size="11" font-family="monospace">y = ${state.y.toFixed(1)} m</text>
    ${state.landed ? `<text x="${w / 2}" y="${hh / 2}" fill="${colors.yellow}" font-size="16" font-family="sans-serif" text-anchor="middle" font-weight="bold">LANDED — Range: ${state.x.toFixed(1)} m</text>` : ''}
  </svg>`
}

export const renderSVGSpring = (state: SpringState, params: SpringParams): string => {
  const w = 600
  const hh = 450
  const cy = hh / 2
  const wallX = 60
  const restX = 300
  const scale = 100
  const massX = restX + state.displacement * scale
  const massSize = 30

  const gridLines: string[] = []
  for (let i = 0; i < w; i += 40) {
    gridLines.push(`<line x1="${i}" y1="0" x2="${i}" y2="${hh}" stroke="${colors.gridLine}" stroke-width="0.5"/>`)
  }
  for (let i = 0; i < hh; i += 40) {
    gridLines.push(`<line x1="0" y1="${i}" x2="${w}" y2="${i}" stroke="${colors.gridLine}" stroke-width="0.5"/>`)
  }

  const coils = 12
  const springLen = massX - wallX - massSize / 2
  const coilWidth = springLen / coils
  const amplitude = 14

  let springPath = `M ${wallX} ${cy}`
  for (let i = 0; i < coils; i++) {
    const x1 = wallX + coilWidth * i + coilWidth * 0.25
    const x2 = wallX + coilWidth * i + coilWidth * 0.75
    const x3 = wallX + coilWidth * (i + 1)
    springPath += ` L ${x1} ${cy - amplitude} L ${x2} ${cy + amplitude} L ${x3} ${cy}`
  }

  return `<svg viewBox="0 0 ${w} ${hh}" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:100%">
    ${gridLines.join('')}
    <rect x="${wallX - 10}" y="${cy - 60}" width="10" height="120" fill="${colors.border}" rx="2"/>
    <line x1="${wallX - 10}" y1="${cy - 60}" x2="${wallX - 10}" y2="${cy + 60}" stroke="${colors.textDim}" stroke-width="2"/>
    <path d="${springPath}" fill="none" stroke="${colors.spring}" stroke-width="2.5" stroke-linecap="round"/>
    <rect x="${massX - massSize / 2}" y="${cy - massSize / 2}" width="${massSize}" height="${massSize}" rx="4" fill="${colors.spring}" opacity="0.9"/>
    <line x1="${restX}" y1="${cy + 50}" x2="${restX}" y2="${cy + 70}" stroke="${colors.textDim}" stroke-width="1" stroke-dasharray="3"/>
    <text x="${restX}" y="${cy + 84}" fill="${colors.textDim}" font-size="10" font-family="monospace" text-anchor="middle">x=0</text>
    <text x="10" y="20" fill="${colors.textDim}" font-size="11" font-family="monospace">x = ${state.displacement.toFixed(3)} m</text>
    <text x="10" y="36" fill="${colors.textDim}" font-size="11" font-family="monospace">v = ${state.velocity.toFixed(3)} m/s</text>
    <text x="10" y="52" fill="${colors.textDim}" font-size="11" font-family="monospace">k = ${params.springConstant} N/m, m = ${params.mass} kg</text>
  </svg>`
}

