export const render = (input: RenderInput) => {
  const { simState, kinematics } = input
  const { activeTab, running, time, speed } = simState

  const sliders = activeTab === 'pendulum'
    ? pendulumSliders(input.pendulumParams)
    : activeTab === 'projectile'
      ? projectileSliders(input.projectileParams)
      : springSliders(input.springParams)

  let svgContent = ''
  if (activeTab === 'pendulum') {
    svgContent = renderSVGPendulum(input.pendulumState, input.pendulumParams)
  } else if (activeTab === 'projectile') {
    svgContent = renderSVGProjectile(input.projectileState, input.projectileParams)
  } else {
    svgContent = renderSVGSpring(input.springState, input.springParams)
  }

  const tabEntries = (['pendulum', 'projectile', 'spring'] as SimulationType[])

  const page = h('div', { style: styleToStr(styles.container) },
    h('header', { style: styleToStr(styles.header) },
      h('h1', { style: styleToStr(styles.title) }, "Newton's Laws Simulator"),
      h('p', { style: styleToStr(styles.subtitle) }, 'Interactive physics simulations — pendulum, projectile & spring-mass'),
    ),
    h('nav', { style: styleToStr(styles.tabs) },
      ...tabEntries.map(t =>
        h('button', {
          style: styleToStr(t === activeTab ? styles.tabActive : styles.tab),
          'p-trigger': `tab-${t}`,
        }, tabLabels[t]),
      ),
    ),
    h('div', { style: styleToStr(styles.layout) },
      h('aside', {},
        h('div', { style: styleToStr(styles.panel) },
          h('h3', { style: styleToStr(styles.panelTitle) }, 'Parameters'),
          ...sliders.map(renderSlider),
        ),
        h('div', { style: styleToStr({ ...styles.panel, marginTop: '12px' }) },
          h('h3', { style: styleToStr(styles.panelTitle) }, 'Real-Time Values'),
          renderKinematics(kinematics, activeTab),
        ),
      ),
      h('main', {},
        h('div', { style: styleToStr(styles.panel) },
          h('div', {
            style: styleToStr(styles.canvas),
            'p-target': 'canvas',
            innerHTML: svgContent,
          }),
          h('div', { style: styleToStr(styles.controls) },
            h('button', {
              style: styleToStr({ ...styles.btn, ...(running ? styles.btnPause : styles.btnPlay) }),
              'p-trigger': 'toggle-play',
            }, running ? 'Pause' : 'Play'),
            h('button', {
              style: styleToStr({ ...styles.btn, ...styles.btnReset }),
              'p-trigger': 'reset',
            }, 'Reset'),
            h('span', { style: styleToStr(styles.speedLabel) }, 'Speed:'),
            h('select', {
              style: styleToStr(styles.speedSelect),
              'p-trigger': 'speed-change',
              value: String(speed),
            },
              h('option', { value: '0.25' }, '0.25×'),
              h('option', { value: '0.5' }, '0.5×'),
              h('option', { value: '1' }, '1×'),
              h('option', { value: '2' }, '2×'),
              h('option', { value: '4' }, '4×'),
            ),
          ),
          h('div', { style: styleToStr(styles.time as Record<string, string>), 'p-target': 'time-display' },
            `t = ${time.toFixed(2)} s`,
          ),
        ),
      ),
    ),
  )

  return page
}

export const renderToString = (input: RenderInput): string => {
  const ssr = createSSR()
  const template = render(input)
  return ssr(template)
}

import type {
  SimulationType,
  SimulationState,
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  KinematicValues,
} from './types'
import {
  createPendulumState,
  stepPendulum,
  pendulumKinematics,
  createProjectileState,
  stepProjectile,
  projectileKinematics,
  createSpringState,
  stepSpring,
  springKinematics,
} from './sim-engine'
import {
  renderToString,
  renderSVGPendulum,
  renderSVGProjectile,
  renderSVGSpring,
  type RenderInput,
} from './renderer'

const DEFAULT_PENDULUM_PARAMS: PendulumParams = {
  length: 1.5,
  gravity: 9.81,
  initialAngle: 30 * (Math.PI / 180),
  damping: 0,
}

const DEFAULT_PROJECTILE_PARAMS: ProjectileParams = {
  angle: 45,
  velocity: 20,
  gravity: 9.81,
  height: 0,
}

const DEFAULT_SPRING_PARAMS: SpringParams = {
  springConstant: 10,
  mass: 1,
  initialDisplacement: 1,
  damping: 0,
}

type Simulator = {
  simState: SimulationState
  pendulumParams: PendulumParams
  pendulumState: PendulumState
  projectileParams: ProjectileParams
  projectileState: ProjectileState
  springParams: SpringParams
  springState: SpringState
  animationFrame: ReturnType<typeof setInterval> | null
}

const createSimulator = (): Simulator => ({
  simState: {
    running: false,
    time: 0,
    speed: 1,
    activeTab: 'pendulum',
  },
  pendulumParams: { ...DEFAULT_PENDULUM_PARAMS },
  pendulumState: createPendulumState(DEFAULT_PENDULUM_PARAMS),
  projectileParams: { ...DEFAULT_PROJECTILE_PARAMS },
  projectileState: createProjectileState(DEFAULT_PROJECTILE_PARAMS),
  springParams: { ...DEFAULT_SPRING_PARAMS },
  springState: createSpringState(DEFAULT_SPRING_PARAMS),
  animationFrame: null,
})

const getKinematics = (sim: Simulator): KinematicValues => {
  const { activeTab } = sim.simState
  if (activeTab === 'pendulum') return pendulumKinematics(sim.pendulumState, sim.pendulumParams)
  if (activeTab === 'projectile') return projectileKinematics(sim.projectileState, sim.projectileParams)
  return springKinematics(sim.springState)
}

const stepSimulation = (sim: Simulator, dt: number): void => {
  const effectiveDt = dt * sim.simState.speed
  sim.simState.time += effectiveDt

  sim.pendulumState = stepPendulum(sim.pendulumState, sim.pendulumParams, effectiveDt)
  if (sim.simState.activeTab === 'projectile') {
    sim.projectileState = stepProjectile(sim.projectileState, sim.projectileParams, effectiveDt)
  }
  sim.springState = stepSpring(sim.springState, sim.springParams, effectiveDt)
}

const getRenderInput = (sim: Simulator): RenderInput => ({
  simState: sim.simState,
  pendulumParams: sim.pendulumParams,
  pendulumState: sim.pendulumState,
  projectileParams: sim.projectileParams,
  projectileState: sim.projectileState,
  springParams: sim.springParams,
  springState: sim.springState,
  kinematics: getKinematics(sim),
})

const handleTabSwitch = (sim: Simulator, tab: SimulationType): void => {
  sim.simState.activeTab = tab
  handleReset(sim)
}

const handleTogglePlay = (sim: Simulator): void => {
  sim.simState.running = !sim.simState.running

  if (sim.simState.running) {
    startLoop(sim)
  } else {
    stopLoop(sim)
  }
}

const handleReset = (sim: Simulator): void => {
  sim.simState.running = false
  sim.simState.time = 0
  stopLoop(sim)

  sim.pendulumState = createPendulumState(sim.pendulumParams)
  sim.projectileState = createProjectileState(sim.projectileParams)
  sim.springState = createSpringState(sim.springParams)
}

const handleSpeedChange = (sim: Simulator, speed: number): void => {
  sim.simState.speed = speed
}

const handleSlider = (sim: Simulator, id: string, value: number): void => {
  const wasRunning = sim.simState.running
  if (wasRunning) {
    sim.simState.running = false
    stopLoop(sim)
  }

  if (id === 'pen-length') sim.pendulumParams.length = value
  else if (id === 'pen-gravity') sim.pendulumParams.gravity = value
  else if (id === 'pen-angle') sim.pendulumParams.initialAngle = value * (Math.PI / 180)
  else if (id === 'proj-angle') sim.projectileParams.angle = value
  else if (id === 'proj-velocity') sim.projectileParams.velocity = value
  else if (id === 'proj-gravity') sim.projectileParams.gravity = value
  else if (id === 'spr-k') sim.springParams.springConstant = value
  else if (id === 'spr-mass') sim.springParams.mass = value
  else if (id === 'spr-disp') sim.springParams.initialDisplacement = value

  handleReset(sim)
}

const FPS = 60
const FRAME_DT = 1 / FPS

const startLoop = (sim: Simulator): void => {
  if (sim.animationFrame) return

  sim.animationFrame = setInterval(() => {
    if (!sim.simState.running) {
      stopLoop(sim)
      return
    }

    stepSimulation(sim, FRAME_DT)
  }, 1000 / FPS)
}

const stopLoop = (sim: Simulator): void => {
  if (sim.animationFrame) {
    clearInterval(sim.animationFrame)
    sim.animationFrame = null
  }
}

const renderFullPage = (sim: Simulator): string => renderToString(getRenderInput(sim))

const renderCanvasSVG = (sim: Simulator): string => {
  const { activeTab } = sim.simState
  if (activeTab === 'pendulum') return renderSVGPendulum(sim.pendulumState, sim.pendulumParams)
  if (activeTab === 'projectile') return renderSVGProjectile(sim.projectileState, sim.projectileParams)
  return renderSVGSpring(sim.springState, sim.springParams)
}

// --- Server entry point ---
const sim = createSimulator()

const serveRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname

  if (path === '/' || path === '/index.html') {
    const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Newton's Laws Simulator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #0f1117; overflow-x: hidden; }
    input[type="range"] {
      -webkit-appearance: none; height: 6px; border-radius: 3px;
      background: #2a2d3a; outline: none;
    }
    input[type="range"]::-webkit-slider-thumb {
      -webkit-appearance: none; width: 16px; height: 16px;
      border-radius: 50%; background: #4f8ff7; cursor: pointer;
    }
    button:hover { opacity: 0.85; }
    select:focus { outline: 1px solid #4f8ff7; }
  </style>
</head>
<body>
  <div id="app">${renderFullPage(sim)}</div>
  <script>
    const eventSource = new EventSource('/events');
    eventSource.onmessage = (e) => {
      const data = JSON.parse(e.data);
      if (data.type === 'full') {
        document.getElementById('app').innerHTML = data.html;
        attachListeners();
      } else if (data.type === 'canvas') {
        const canvas = document.querySelector('[p-target="canvas"]');
        if (canvas) canvas.innerHTML = data.svg;
      } else if (data.type === 'readout') {
        const readout = document.querySelector('[p-target="readout"]');
        if (readout) readout.innerHTML = data.html;
      } else if (data.type === 'time') {
        const el = document.querySelector('[p-target="time-display"]');
        if (el) el.textContent = data.text;
      }
    };

    const post = (action, payload = {}) =>
      fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, ...payload }),
      });

    const attachListeners = () => {
      document.querySelectorAll('[p-trigger^="tab-"]').forEach(btn => {
        btn.onclick = () => post('tab', { tab: btn.getAttribute('p-trigger').replace('tab-', '') });
      });
      document.querySelector('[p-trigger="toggle-play"]')?.addEventListener('click', () => post('toggle'));
      document.querySelector('[p-trigger="reset"]')?.addEventListener('click', () => post('reset'));
      document.querySelector('[p-trigger="speed-change"]')?.addEventListener('change', (e) => {
        post('speed', { speed: parseFloat(e.target.value) });
      });
      document.querySelectorAll('[p-trigger^="slide-"]').forEach(input => {
        const id = input.getAttribute('p-trigger').replace('slide-', '');
        input.oninput = (e) => {
          const val = parseFloat(e.target.value);
          const label = document.querySelector('[p-target="val-' + id + '"]');
          if (label) label.textContent = val + ' ' + (input.dataset.unit || input.closest('[style]')?.querySelector('[p-target]')?.textContent?.split(' ').pop() || '');
          post('slider', { id, value: val });
        };
      });
    };

    attachListeners();
  </script>
</body>
</html>`
    return new Response(html, { headers: { 'Content-Type': 'text/html' } })
  }

  if (path === '/events') {
    const stream = new ReadableStream({
      start(controller) {
        const encoder = new TextEncoder()
        const send = (data: unknown) => {
          controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`))
        }

        const interval = setInterval(() => {
          if (sim.simState.running) {
            send({ type: 'canvas', svg: renderCanvasSVG(sim) })
            send({ type: 'time', text: `t = ${sim.simState.time.toFixed(2)} s` })
            send({
              type: 'readout',
              html: renderReadoutHTML(sim),
            })
          }
        }, 1000 / 30)

        const cleanup = () => clearInterval(interval)
        req.signal.addEventListener('abort', cleanup)
      },
    })

    return new Response(stream, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        Connection: 'keep-alive',
      },
    })
  }

  if (path === '/action' && req.method === 'POST') {
    const body = await req.json() as Record<string, unknown>
    const action = body.action as string

    if (action === 'tab') handleTabSwitch(sim, body.tab as SimulationType)
    else if (action === 'toggle') handleTogglePlay(sim)
    else if (action === 'reset') handleReset(sim)
    else if (action === 'speed') handleSpeedChange(sim, body.speed as number)
    else if (action === 'slider') handleSlider(sim, body.id as string, body.value as number)

    if (action === 'tab' || action === 'reset' || action === 'slider') {
      return new Response(JSON.stringify({ reload: true }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    return new Response(JSON.stringify({ ok: true }), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (path === '/state') {
    return new Response(JSON.stringify(getRenderInput(sim)), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  return new Response('Not Found', { status: 404 })
}

const renderReadoutHTML = (sim: Simulator): string => {
  const k = getKinematics(sim)
  const { activeTab } = sim.simState
  const fmt = (n: number) => n.toFixed(2)

  const row = (label: string, value: string) =>
    `<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid #2a2d3a;font-size:12px">
      <span style="color:#8b8fa3">${label}</span>
      <span style="color:#e1e4ed;font-weight:600;font-family:'JetBrains Mono',monospace">${value}</span>
    </div>`

  if (activeTab === 'pendulum') {
    const angle = Math.atan2(k.position.x, -k.position.y)
    const speed = Math.sqrt(k.velocity.x ** 2 + k.velocity.y ** 2)
    const acc = Math.sqrt(k.acceleration.x ** 2 + k.acceleration.y ** 2)
    return [
      row('Angle (θ)', `${fmt(angle * (180 / Math.PI))}°`),
      row('Position (x, y)', `(${fmt(k.position.x)}, ${fmt(k.position.y)}) m`),
      row('Velocity', `${fmt(speed)} m/s`),
      row('Acceleration', `${fmt(acc)} m/s²`),
    ].join('')
  }

  if (activeTab === 'projectile') {
    const speed = Math.sqrt(k.velocity.x ** 2 + k.velocity.y ** 2)
    return [
      row('Position (x)', `${fmt(k.position.x)} m`),
      row('Position (y)', `${fmt(k.position.y)} m`),
      row('Velocity (vx)', `${fmt(k.velocity.x)} m/s`),
      row('Velocity (vy)', `${fmt(k.velocity.y)} m/s`),
      row('Speed', `${fmt(speed)} m/s`),
      row('Acceleration', `${fmt(k.acceleration.y)} m/s²`),
    ].join('')
  }

  return [
    row('Displacement', `${fmt(k.position.x)} m`),
    row('Velocity', `${fmt(k.velocity.x)} m/s`),
    row('Acceleration', `${fmt(k.acceleration.x)} m/s²`),
  ].join('')
}

const PORT = parseInt(process.env.PORT || '3000', 10)

Bun.serve({
  port: PORT,
  fetch: serveRequest,
})

console.log(`Newton's Laws Simulator running at http://localhost:${PORT}`)

export {
  createSimulator,
  handleTabSwitch,
  handleTogglePlay,
  handleReset,
  handleSpeedChange,
  handleSlider,
  stepSimulation,
  getKinematics,
  getRenderInput,
}
